$_MODULE['<{mondialrelay}prestashop>content_1e25f375279ba33cb0da5862bd3a356a'] = '[1]  Pour vous accompagner, on met le paquet !  Mondial Relay - InPost, leader de la livraison hors-domicile en Europe [/1]';
$_MODULE['<{mondialrelay}prestashop>content_30b8a21d08ef40faf8e80282b5b18fe4'] = 'Mondial Relay - InPost, tout le monde connaît. C’est le spécialiste de la livraison de colis aux particuliers depuis plus de 25 ans à travers ses solutions de distribution en Points Relais®, Lockers et à Domicile en Europe.';
$_MODULE['<{mondialrelay}prestashop>content_023bb091065af2a91af12121dc4dee1f'] = 'Mais c’est aussi plus de 9 pays européens de distribution, plus de 150 000 e-commerçants qui nous confient leurs colis, plus de 45 000 points de retrait en Europe, plus d’innovations pour simplifier la vie de chacun et plus de praticité et de sécurité pour les clients au meilleur prix.';
$_MODULE['<{mondialrelay}prestashop>content_1ddafceab03be7e828ce610048d8e149'] = 'Proposez à vos clients une offre de livraison économique simple, sûre et pratique :';
$_MODULE['<{mondialrelay}prestashop>content_5663efd5d0ae25b5d1643b23c385da5e'] = '[1] Economique [/1] : Finis les envois de colis qui coûtent un bras ! Avec Mondial Relay - InPost, les consommateurs profitent d’un rapport qualité/prix imbattable';
$_MODULE['<{mondialrelay}prestashop>content_140f0f35ff86c9af93245d6b08b9ea26'] = '[1] Simple [/1] : on n’a qu’une idée en tête « simplifier la vie de chacun ». Envoyer ou recevoir un colis avec Mondial Relay - InPost, c’est simple comme un sourire.';
$_MODULE['<{mondialrelay}prestashop>content_2d2c3abb1283d8a4b38868ee98eefe5a'] = '[1] Sûre et pratique [/1] : Mondial Relay - InPost prend soin de vos expéditions. Avec un tracing rigoureux, le client peut suivre son colis à la trace et le retirer dans l\'un de nos Points Relais® et Lockers grâce à un code PIN ou QR Code.';
$_MODULE['<{mondialrelay}prestashop>content_b1ed83ef2fcfcfff29a73e07aaeecde0'] = 'Mondial Relay est évalué chaque jour par des centaines de clients grâce à l\'intermédiaire de l\'organisme Avis Vérifiés, certifié AFNOR délivrant une note de 9.1/10';
$_MODULE['<{mondialrelay}prestashop>content_b081f23af33c6e7502acab8b71a9aea5'] = 'Découvrez les offres Mondial Relay - Inpost';
$_MODULE['<{mondialrelay}prestashop>content_d943ddad1a8060a8dd51f3c12713e6a0'] = 'Proposez à vos clients une offre de livraison économique simple, sûre et pratique :';
$_MODULE['<{mondialrelay}prestashop>content_9f35639eb56fc42b6a5731a474d810bc'] = 'Découvrez les offres Mondial Relay';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_82af2c60811a72571e4ea942d0d55410'] = 'Veuillez choisir un mode d\'affichage des Points Relais pour votre boutique.';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_b35ac93e97894f42d54ff9c82a9cd81e'] = 'Mode normal : adapté aux mobiles sans carte';
$_MODULE['<{mondialrelay}prestashop>display_mode_description_846b8507e2f43c525989d678fc07026f'] = 'Mode Widget : adapté aux mobiles avec une carte';
$_MODULE['<{mondialrelay}prestashop>content_50210436fc7e78da4182f21963b3a136'] = 'Depuis 1997, Mondial Relay est le spécialiste de la livraison de colis aux particuliers avec le plus grand réseau européen de livraison du e-commerce, l\'un des leaders de la distribution des colis du e-commerce en France, en Europe et accompagne plus de 40 000 e-commerçants. Avec des solutions de distribution de colis, en France et en Europe, en Points Relais, en Drive et à Domicile.';
$_MODULE['<{mondialrelay}prestashop>content_ff390019e65d83b32ddc50435476c2fe'] = 'Proposez à vos clients une offre de livraison économique simple, sûre et pratique :';
$_MODULE['<{mondialrelay}prestashop>content_4a3366d5a627724bf9a32f4b6d6ed0ee'] = '[1] Economique [/1] : Fini le monopole de l\'envoi de colis, des tarifs à partir de 3.79Eur HT !';
$_MODULE['<{mondialrelay}prestashop>content_2016814d95f7ccb9d1d5de518a8d0a53'] = '[1] Simple [/1] : Envoyer ou recevoir un colis n\'a jamais été aussi simple avec toutes les solutions offertes par Mondial Relay. Le retrait en Point Relais® est de plus en plus plébiscité par les clients !';
$_MODULE['<{mondialrelay}prestashop>content_dadf83db013c1824f0a44d269c5f83d7'] = '[1] Sûre et pratique [/1] : Mondial Relay prend soin de vos expéditions. Avec un tracing rigoureux, le client peut suivre son colis à la trace et le retirer dans l\'un de nos Points Relais ou à domicile à l\'international';
$_MODULE['<{mondialrelay}prestashop>content_17ee3ace47ac0bfecdf46ce2c0ee56e5'] = 'Mondial Relay est évalué chaque jour par des centaines de clients par l\'intermédiaire de l\'organisme certifié AFNOR Avis Vérifiés et a une note de 4.4/5';
$_MODULE['<{mondialrelay}prestashop>list_header_5ae4c97a0358acbea4034a55a1c02be1'] = 'Vous pouvez créer une tâche CRON sur votre serveur pour mettre à jour les statuts de commandes quand la commande est expédiée.';
$_MODULE['<{mondialrelay}prestashop>list_header_690361676eb5b079dc16d187d759035b'] = 'La tâche CRON est utilisée pour paramétrer la fréquence d\'appels à notre service de suivi de colis de façon à voir les colis \"livrés\". Nous préconisons une mise à jour toutes les 6h.';
